from rest_framework import viewsets, status
from rest_framework.decorators import action
from rest_framework.response import Response


class OrderViewSet(viewsets.ModelViewSet):
    serializer_class = OrderSerializer
    permission_classes = [IsAuthenticated]

    def get_queryset(self):
        # Always scope to the requesting user
        return Order.objects.filter(user=self.request.user)

    @action(detail=True, methods=["post"])
    def cancel(self, request, pk=None):
        """Non-CRUD verb as @action — keeps URL conf flat."""
        order = self.get_object()
        order_services.cancel_order(order_id=order.id)
        return Response({"status": "cancelled"})

    def get_permissions(self):
        """Per-action permissions — more granular than class-level."""
        if self.action == "create":
            return [IsAuthenticated(), HasOrderPermission()]
        return [IsAuthenticated()]

class ProductViewSet(viewsets.ModelViewSet):
    http_method_names = ["get", "post", "patch", "head", "options"]
    # DELETE is intentionally excluded
